// Checks to see if a given player is a non-NPC name on the whitelist
// salt is technically not necessary beyond peppering the hashes as none of this is private or personally identifying information
// but there's one anyway for best practice and transparency
fun String.isPlayerNameOnWhitelist(): Boolean {
  val playerHash = sha256(this, "player_seed_salt_december_2025")
  return NON_NPC_NAMES_WHITELIST.contains(playerHash)
}
